const body = $input.first().json.body || {};
const call = body.call || {};
const dv = call.retell_llm_dynamic_variables || {};
const analysis = call.call_analysis || {};
const custom = analysis.custom_analysis_data || {};

// Required: lead_email must come through Retell dynamic variables
const lead_email = (dv.lead_email || '').toLowerCase().trim();
if (!lead_email) {
  throw new Error('Missing lead_email in Retell dynamic_variables. ' +
    'For test web calls, set lead_email in the Retell test UI before starting the call. ' +
    'For outbound dials, the n8n outbound chain must include lead_email in retell_llm_dynamic_variables.');
}

// Deterministic UUID-shape from call_id: strip non-hex, pad to 32 hex chars
const callId = call.call_id || ('no-call-id-' + Date.now());
let hex = callId.replace(/[^0-9a-fA-F]/g, '').toLowerCase();
hex = (hex + '00000000000000000000000000000000').slice(0, 32);
const event_id = `${hex.slice(0,8)}-${hex.slice(8,12)}-${hex.slice(12,16)}-${hex.slice(16,20)}-${hex.slice(20,32)}`;

const phoneRaw = call.to_number || '';
const phone_e164 = /^\+[1-9]\d{7,14}$/.test(phoneRaw) ? phoneRaw : null;

const tsMs = call.end_timestamp || call.start_timestamp;
const timestamp = tsMs ? new Date(tsMs).toISOString() : new Date().toISOString();

return [{ json: {
  event_id,
  lead_email,
  channel: 'voice',
  direction: 'outbound',
  content: analysis.call_summary || call.transcript || '',
  content_type: 'summary',
  timestamp,
  intent: custom.qualified_status === true ? 'interested' : 'unknown',
  phone_e164,
  sender_name: 'Maya (Flowtics AI)',
  metadata: {
    call_id: call.call_id || null,
    agent_id: call.agent_id || null,
    qualified_status: custom.qualified_status,
    recording_url: call.recording_url || null,
    source: 'retell_flowtics'
  }
}}];

const ctx = $input.first().json.context_block || 'No prior conversation on record.';

const NL = String.fromCharCode(10);

const systemPrompt = "You summarize prior sales conversations for a voice AI agent doing a follow-up call. " +
  "Output a tight, factual brief (<=180 words) covering: " +
  "(1) who the lead is and what business they run, " +
  "(2) what they expressed interest in, " +
  "(3) pain points or goals they mentioned, " +
  "(4) any objections or concerns raised, " +
  "(5) commitments or next steps that were promised, " +
  "(6) the last channel and rough recency of contact. " +
  "Bullet points are fine. Do NOT invent details. " +
  "If the context is empty or says no prior conversation, return the single line: No prior conversation on record.";

const userContent = "Prior cross-channel context for this lead:" + NL + NL + ctx;

return [{ json: {
  openai_body: {
    model: 'gpt-4o-mini',
    temperature: 0.2,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userContent }
    ]
  },
  context_block: $input.first().json.context_block,
  lead: $input.first().json.lead
}}];

// Pull from Prepare Retell Variables (immediate upstream via Set node)
const v = $input.first().json;

// Retell-purchased number (clean E.164 — strip any parens/dashes/spaces if user re-enters)
const rawFrom = '+15722124790';
const fromNumber = '+' + rawFrom.replace(/[^0-9]/g, '');

return [{ json: {
  retell_body: {
    from_number: fromNumber,
    to_number: v.phone_e164,
    override_agent_id: 'agent_ff863b1414049444c174360809',
    retell_llm_dynamic_variables: {
      first_name: v.first_name || 'there',
      company_name: v.company_name || 'your business',
      booking_link: 'https://calendly.com/mahfujurrahman511351/30min',
      previous_conversation_summary: v.previous_conversation_summary || 'No prior conversation on record.',
      lead_email: v.lead_email
    },
    metadata: {
      source: 'n8n_flowtics_followup',
      client: 'flowtics',
      queue_id: v.queue_id,
      lead_email: v.lead_email
    }
  },
  queue_id: v.queue_id,
  lead_email: v.lead_email,
  phone_e164: v.phone_e164
}}];

